INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (1, 'en_US', 'title', 'A Reproducible Pipeline for Streaming Log Analytics at Scale');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (1, 'en_US', 'abstract', '<p>Operational logs are a primary signal for diagnosing distributed systems, yet pipelines that process them are often ad hoc and hard to reproduce.</p><p>We present a modular pipeline that combines schema-on-read ingestion with incremental aggregation, and evaluate it on three public workloads.</p><p>Results indicate consistent latency under sustained load and a clear path to horizontal scaling.</p>');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (1, '', 'issueId', 1);
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (1, '', 'pages', '1-18');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (2, 'en_US', 'title', 'Index Selection Under Mixed Read-Write Workloads: An Empirical Study');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (2, 'en_US', 'abstract', '<p>Choosing secondary indexes is a classic trade-off between read acceleration and write amplification.</p><p>We benchmark eight index configurations across OLTP and HTAP-style workloads and report when composite indexes stop paying off.</p>');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (2, '', 'issueId', 1);
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (2, '', 'pages', '19-37');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (3, 'en_US', 'title', 'A Systematic Review of Feature Stores for Production Machine Learning');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (3, 'en_US', 'abstract', '<p>Feature stores promise to bridge experimentation and serving, but the literature is fragmented across vendors and open-source projects.</p><p>We systematically review 64 primary sources, propose a capability taxonomy, and highlight open gaps in lineage and point-in-time correctness.</p>');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (3, '', 'issueId', 2);
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (3, '', 'pages', '39-71');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (4, 'en_US', 'title', 'Migrating a Municipal Records System to Event Sourcing: A Case Study');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (4, 'en_US', 'abstract', '<p>We report on an eighteen-month migration of a municipal records system from a CRUD architecture to event sourcing.</p><p>The case covers data backfill, auditability requirements, and the organisational change needed to sustain the new model.</p>');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (4, '', 'issueId', 2);
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (4, '', 'pages', '73-88');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (5, 'en_US', 'title', 'Tail-Latency Aware Load Balancing for Microservice Meshes');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (5, 'en_US', 'abstract', '<p>Mesh sidecars make per-request routing decisions cheap, opening the door to latency-aware policies.</p><p>We propose a balancer that estimates downstream queue depth from recent response times and show reduced p99 latency without throughput loss.</p>');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (5, '', 'issueId', 3);
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (5, '', 'pages', '1-24');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (6, 'en_US', 'title', 'A Note on Deterministic Seeding for Reproducible Benchmarks');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (6, 'en_US', 'abstract', '<p>Non-deterministic seeding silently undermines benchmark comparability.</p><p>We describe a lightweight convention for seeding and recording entropy sources that makes runs byte-reproducible across machines.</p>');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (6, '', 'issueId', 3);
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (6, '', 'pages', '25-32');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (7, 'en_US', 'title', 'Cognitive Load in Code Review: An Eye-Tracking Study');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (7, 'en_US', 'abstract', '<p>Code review quality depends on reviewer attention, which is hard to measure directly.</p><p>Using eye-tracking on 28 developers, we relate fixation patterns to defect-detection rates and discuss interface implications for review tools.</p>');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (7, '', 'issueId', 4);
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (7, '', 'pages', '1-29');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (8, 'en_US', 'title', 'Calibrated Uncertainty for Tabular Anomaly Detection');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (8, 'en_US', 'abstract', '<p>Anomaly detectors often output uncalibrated scores that are hard to threshold operationally.</p><p>We combine isotonic calibration with conformal prediction and show reliable coverage on five tabular datasets without retraining the base model.</p>');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (8, '', 'issueId', 5);
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (8, '', 'pages', '1-26');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (9, 'en_US', 'title', 'Editorial: Toward Boringly Reliable Machine Learning Systems');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (9, 'en_US', 'abstract', '<p>In this editorial we argue that the next gains in applied machine learning will come less from novel models and more from boringly reliable systems engineering around them.</p>');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (9, '', 'issueId', 5);
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (9, '', 'pages', 'i-iii');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (10, 'en_US', 'title', 'Differentially Private Aggregation for Telemetry Dashboards');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (10, 'en_US', 'abstract', '<p>Product telemetry dashboards expose aggregates that can leak information about individual users.</p><p>We study differentially private aggregation under realistic refresh rates and quantify the utility cost of common privacy budgets.</p>');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (11, 'en_US', 'title', 'A Review of Vector Database Indexes for Approximate Nearest Neighbor Search');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (11, 'en_US', 'abstract', '<p>Vector databases have proliferated alongside embedding-based applications.</p><p>This review compares graph-, tree-, and quantization-based indexes on recall, build cost, and memory, and identifies workloads where each family dominates.</p>');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (12, 'en_US', 'title', 'Energy-Proportional Scheduling for Batch Analytics (Work in Progress)');
INSERT INTO `publication_settings` (`publication_id`, `locale`, `setting_name`, `setting_value`) VALUES (12, 'en_US', 'abstract', '<p>This work-in-progress explores scheduling batch analytics jobs to track time-varying grid carbon intensity while meeting deadlines.</p>');
